import React, { useState } from 'react';
import { PageHeader, Modal } from '../../components/UI';

const muscles = [
  {
    id: 1, nom: 'Biceps', icon: 'bi-lightning-charge', zone: 'Bras',
    image: 'https://weighttraining.guide/wp-content/uploads/2016/11/Barbell-Curl-resized.png',
    exercices: [
      { nom: 'Curl barre', series: '4×10', desc: 'Debout, barre en supination. Fléchir les coudes jusqu\'à la hauteur des épaules sans bouger les coudes.' },
      { nom: 'Curl haltères alternés', series: '3×12', desc: 'Alterner gauche-droite en contrôlant la descente. Tourner le poignet en haut du mouvement.' },
      { nom: 'Curl marteau', series: '3×12', desc: 'Prise neutre (pouce vers le haut). Cible aussi le brachial et l\'avant-bras.' },
      { nom: 'Curl concentré', series: '3×15', desc: 'Assis, coude appuyé sur la cuisse. Excellent pour le pic du biceps.' },
    ]
  },
  {
    id: 2, nom: 'Triceps', icon: 'bi-lightning', zone: 'Bras',
    image: 'https://weighttraining.guide/wp-content/uploads/2016/10/Cable-Pushdown-with-a-rope-attachment-resized.png',
    exercices: [
      { nom: 'Dips', series: '4×12', desc: 'Corps vertical, coudes près du corps. Plus efficace avec lest quand maîtrisé.' },
      { nom: 'Extension nuque', series: '3×12', desc: 'Haltère ou barre EZ derrière la tête. Cible le chef long du triceps.' },
      { nom: 'Pushdown câble', series: '4×15', desc: 'Câble haute poulie, coudes fixes. Excellent pour la finition et le pump.' },
      { nom: 'Pompes diamant', series: '3×15', desc: 'Mains en triangle sous le sternum. Variante au poids du corps très efficace.' },
    ]
  },
  {
    id: 3, nom: 'Pectoraux', icon: 'bi-person-arms-up', zone: 'Buste',
    image: 'https://weighttraining.guide/wp-content/uploads/2021/06/machine-chest-press-resized.png',
    exercices: [
      { nom: 'Développé couché', series: '5×8', desc: 'Le roi des exercices de poitrine. Descendre la barre jusqu\'à effleurer le sternum.' },
      { nom: 'Développé incliné', series: '4×10', desc: 'Banc à 30-45°. Cible le faisceau supérieur pour un pec plus complet.' },
      { nom: 'Écarté haltères', series: '3×12', desc: 'Légère flexion des coudes. Mouvement d\'isolation, descente lente et contrôlée.' },
      { nom: 'Crossover câbles', series: '3×15', desc: 'Croisement des mains en bas. Étirement maximal du grand pectoral.' },
    ]
  },
  {
    id: 4, nom: 'Dos', icon: 'bi-arrows-expand-vertical', zone: 'Dos',
    image: 'https://weighttraining.guide/wp-content/uploads/2016/10/Lat-Pulldown-resized.png',
    exercices: [
      { nom: 'Tractions', series: '4×8', desc: 'Prise large pronation. Le squat du dos. Ajouter du lest progressivement.' },
      { nom: 'Rowing barre', series: '4×10', desc: 'Tronc parallèle au sol, tirer vers le nombril. Excellent pour l\'épaisseur.' },
      { nom: 'Tirage poulie haute', series: '3×12', desc: 'Tirer vers le haut du sternum. Alternatif aux tractions pour les débutants.' },
      { nom: 'Soulevé de terre', series: '4×6', desc: 'Le mouvement roi. Dos droit, gainage total, poussée des talons dans le sol.' },
    ]
  },
  {
    id: 5, nom: 'Épaules', icon: 'bi-award', zone: 'Épaules',
    image: 'https://weighttraining.guide/wp-content/uploads/2021/06/shoulder-press-machine-resized.png',
    exercices: [
      { nom: 'Développé militaire', series: '4×10', desc: 'Debout ou assis, barre ou haltères. Cible le faisceau antérieur en priorité.' },
      { nom: 'Élévation latérale', series: '4×15', desc: 'Petits poids, coudes légèrement fléchis. Faisceau latéral = épaules larges.' },
      { nom: 'Oiseau (Rear delt)', series: '3×15', desc: 'Tronc penché, bras en croix. Indispensable pour équilibrer posture et force.' },
      { nom: 'Shrugs', series: '4×12', desc: 'Haussement d\'épaules avec haltères ou barre. Cible les trapèzes supérieurs.' },
    ]
  },
  {
    id: 6, nom: 'Jambes', icon: 'bi-activity', zone: 'Jambes',
    image: 'https://weighttraining.guide/wp-content/uploads/2016/10/Leg-Press-resized.png',
    exercices: [
      { nom: 'Squat', series: '5×8', desc: 'Le roi des exercices. Descendre cuisses parallèles, dos droit, genoux dans l\'axe.' },
      { nom: 'Presse à cuisses', series: '4×12', desc: 'Pieds hauts = ischios/fessiers. Pieds bas = quadriceps. Contrôler la montée.' },
      { nom: 'Fentes marchées', series: '3×10', desc: 'Chaque jambe. Grand pas, genou avant à 90°. Excellent pour l\'équilibre.' },
      { nom: 'Leg extension', series: '3×15', desc: 'Isolation quadriceps. Finition en fin de séance pour le pump.' },
      { nom: 'Leg curl', series: '3×15', desc: 'Isolation ischios-jambiers. Ne pas négliger les muscles postérieurs.' },
    ]
  },
  {
    id: 7, nom: 'Abdominaux', icon: 'bi-grid-3x3', zone: 'Core',
    image: 'https://weighttraining.guide/wp-content/uploads/2021/07/machine-crunch-resized.png',
    exercices: [
      { nom: 'Gainage planche', series: '4×60s', desc: 'Corps aligné, contractez abdos et fessiers. Base indispensable du gainage.' },
      { nom: 'Crunch câble', series: '4×20', desc: 'Plus efficace que le crunch classique car résistance constante sur tout le mouvement.' },
      { nom: 'Relevé de jambes', series: '3×15', desc: 'Suspendu ou allongé. Cible le bas du ventre (droit inférieur).' },
      { nom: 'Russian twist', series: '3×20', desc: 'Avec médecine-ball ou haltère. Cible les obliques et la rotation du tronc.' },
    ]
  },
  {
    id: 8, nom: 'Mollets', icon: 'bi-arrow-up-circle', zone: 'Jambes',
    image: 'https://weighttraining.guide/wp-content/uploads/2016/10/Standing-Calf-Raise-resized.png',
    exercices: [
      { nom: 'Extensions mollets debout', series: '5×20', desc: 'Amplitude complète, tenir 1s en haut. Les mollets récupèrent vite, volume élevé.' },
      { nom: 'Extensions assis', series: '4×20', desc: 'Cible le soléaire (muscle profond). Indispensable pour des mollets complets.' },
    ]
  },
];

export default function Musculation() {
  const [selected, setSelected] = useState(null);

  return (
    <div>
      <PageHeader eyebrow="Guide d'entraînement" title="Exercices par" accent="Groupe Musculaire" />

      <div style={{padding:'16px 28px 8px',fontSize:13,color:'var(--text-muted)'}}>
        Cliquez sur un groupe musculaire pour voir les exercices recommandés, les séries et les conseils techniques.
      </div>

      <div style={{display:'grid',gridTemplateColumns:'repeat(4,1fr)',gap:14,padding:'12px 28px 32px'}}>
        {muscles.map(m => (
          <div key={m.id} className="fz-card hoverable" style={{overflow:'hidden',padding:0}} onClick={() => setSelected(m)}>
            <div className="muscle-img-placeholder">
              {m.image
                ? <img src={m.image} alt={m.nom} style={{width:'100%',height:'100%',objectFit:'contain',background:'#1a1a1a'}} />
                : <>
                    <i className={`bi ${m.icon}`}></i>
                    <span>[ Photo {m.nom} ]</span>
                  </>
              }
            </div>
            <div style={{padding:'12px 14px'}}>
              <div style={{fontFamily:'var(--font-heading)',fontSize:16,fontWeight:700,marginBottom:2}}>{m.nom}</div>
              <div style={{fontSize:10,color:'var(--text-dim)',marginBottom:8}}>{m.zone} · {m.exercices.length} exercices</div>
              {m.exercices.slice(0,2).map(e => (
                <div key={e.nom} style={{fontSize:11,color:'var(--text-muted)',marginBottom:2}}>
                  <i className="bi bi-chevron-right me-1" style={{fontSize:9,color:'var(--red)'}}></i>{e.nom}
                </div>
              ))}
              <div style={{fontSize:10,color:'var(--text-dim)',marginTop:4}}>+{m.exercices.length-2} autres...</div>
            </div>
          </div>
        ))}
      </div>

      <Modal show={!!selected} title={selected?.nom} onClose={() => setSelected(null)} size="lg">
        {selected && (
          <div>
            <div style={{display:'flex',gap:12,marginBottom:20,flexWrap:'wrap'}}>
              <span className="fz-badge type">{selected.zone}</span>
              <span style={{fontSize:12,color:'var(--text-muted)'}}>{selected.exercices.length} exercices</span>
            </div>

            <div className="muscle-img-placeholder" style={{marginBottom:20,borderRadius:8,border:'0.5px solid var(--border)',height:200,overflow:'hidden'}}>
              {selected.image
                ? <img src={selected.image} alt={selected.nom} style={{width:'100%',height:'100%',objectFit:'contain',background:'#1a1a1a'}} />
                : <><i className={`bi ${selected.icon}`} style={{fontSize:48,color:'var(--red)',opacity:.5}}></i><span>[ Insérez votre image {selected.nom} ici ]</span></>
              }
            </div>

            <div style={{display:'flex',flexDirection:'column',gap:14}}>
              {selected.exercices.map((e, i) => (
                <div key={e.nom} style={{background:'var(--surface2)',borderRadius:10,padding:'14px 16px',borderLeft:'3px solid var(--red)'}}>
                  <div style={{display:'flex',alignItems:'center',justifyContent:'space-between',marginBottom:6}}>
                    <div style={{fontFamily:'var(--font-heading)',fontSize:15,fontWeight:700}}>{e.nom}</div>
                    <span className="fz-badge type">{e.series}</span>
                  </div>
                  <p style={{fontSize:12,color:'var(--text-muted)',margin:0,lineHeight:1.6}}>{e.desc}</p>
                </div>
              ))}
            </div>
          </div>
        )}
      </Modal>
    </div>
  );
}
